mapper.select:
SELECT A.IID, A.SDATE, A.ITEMCODE, B.ITEMNAME, C.SUBNAME_CH AS CAR, NVL(A.QTY, 0) AS QTY, NVL(A.OKQTY, 0) AS OKQTY, NVL(A.NGQTY, 0) AS NGQTY, A.LINE, A.SOURCE, A.SOURCE2, A.MAINCATEGORY, A.SUBCATEGORY, A.DETAILCATEGORY, A.JUDGMENT, A.CUSTCODE, A.CUSTNAME, A.MEMO, H.SUBNAME_CH AS UNIT, CASE WHEN A.YMDHMS IS NULL OR TRIM(A.YMDHMS) = '' THEN '' ELSE TO_CHAR( TO_DATE(A.YMDHMS, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS' ) END AS HHMM, A.BARCODE, A.BARCODE2 AS DEFBARCODE,
/* ✅ totals (모든 줄에 동일하게 표시) */ SUM(NVL(A.QTY, 0)) OVER () AS TOTALQTY, SUM(NVL(A.OKQTY, 0)) OVER () AS TOTALOKQTY, SUM(NVL(A.NGQTY, 0)) OVER () AS TOTALNGQTY FROM T_WMS_INSPECTION A LEFT OUTER JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE LEFT OUTER JOIN T_MI_TYPESUB C ON B.CARNO = C.SUBCODE AND C.TYPECODE = 'MI041' LEFT OUTER JOIN T_MI_TYPESUB H ON B.CMB_UNIT = H.SUBCODE AND H.TYPECODE = 'MI001' LEFT OUTER JOIN ( SELECT DISTINCT UNPACKBARCODE FROM T_SCM_BARCODE ) D ON D.UNPACKBARCODE = A.BARCODE -- AND A.ymdhms = D.mktime 260311 hj 필요없을거 같아서 주석했는데 필요하면 풀고 SELECT DISTINCT UNPACKBARCODE뒤에 mktime넣어야함 WHERE A.USEYN = 'Y' AND UPPER(A.SOURCE) = 'INCOMING'
ORDER BY A.YMDHMS DESC

SELECT A.SDATE, A.ITEMCODE, B.ITEMNAME, C.SUBNAME_CH AS CAR, NVL(A.QTY, 0) AS QTY, NVL(A.OKQTY, 0) AS OKQTY, NVL(A.NGQTY, 0) AS NGQTY, A.LINE, A.SOURCE, A.SOURCE2, A.MAINCATEGORY, A.SUBCATEGORY, A.DETAILCATEGORY, A.JUDGMENT, A.CUSTNAME, A.MEMO, H.SUBNAME_CH AS UNIT, CASE WHEN A.YMDHMS IS NULL OR TRIM(A.YMDHMS) = '' THEN '' ELSE TO_CHAR( TO_DATE(A.YMDHMS, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS' ) END AS HHMM, A.BARCODE, A.BARCODE2 AS DEFBARCODE,
/* ✅ totals (모든 줄에 동일하게 표시) */ SUM(NVL(A.QTY, 0)) OVER () AS TOTALQTY, SUM(NVL(A.OKQTY, 0)) OVER () AS TOTALOKQTY, SUM(NVL(A.NGQTY, 0)) OVER () AS TOTALNGQTY FROM T_WMS_INSPECTION A LEFT OUTER JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE LEFT OUTER JOIN T_MI_TYPESUB C ON B.CARNO = C.SUBCODE AND C.TYPECODE = 'MI041' LEFT OUTER JOIN T_MI_TYPESUB H ON B.CMB_UNIT = H.SUBCODE AND H.TYPECODE = 'MI001' LEFT OUTER JOIN ( SELECT DISTINCT UNPACKBARCODE FROM T_SCM_BARCODE ) D ON D.UNPACKBARCODE = A.BARCODE WHERE A.USEYN = 'Y' AND A.STORAGE = 'REDCAGE'
ORDER BY A.YMDHMS DESC

SELECT * FROM ( SELECT a.factory, a.storage, a.location, a.indate, a.car, a.itemcode, a.itemname, a.qty, a.barcode, a.ymdhms, a.loginid, a.hhmm, a.bdate, spec, ROW_NUMBER() OVER (ORDER BY a.ymdhms DESC, itemcode) AS rn FROM ( SELECT a.factory, a.storage, a.location, a.indate, c.subname_ch AS car, a.itemcode, b.itemname, a.qty, a.barcode, a.ymdhms, a.loginid, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm, CASE WHEN INSTR(a.barcode, ',') > 0 THEN TRIM(REGEXP_SUBSTR(a.barcode, '[^,]+', 1, 2)) ELSE '' END AS bdate, b.spec FROM t_wms_location a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' WHERE a.useyn = 'Y'
) a
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage} ORDER BY rn

SELECT a.factory, a.storage, a.location, a.indate, c.subname_ch AS car, a.itemcode, b.itemname, CASE WHEN a.okyn = 'Y' THEN NVL(a.qty, '0') ELSE '0' END AS okqty, CASE WHEN a.okyn = 'N' THEN NVL(a.qty, '0') ELSE '0' END AS ngqty, a.ymdhms, a.loginid, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm, A.BARCODE, b.spec, a.okyn,
/* ✅ totals (모든 줄에 동일하게 표시) */ SUM(NVL(A.QTY, 0)) OVER () AS TOTALQTY, SUM(CASE WHEN a.okyn = 'Y' THEN NVL(a.qty, '0') ELSE '0' END) OVER () AS TOTALOKQTY, SUM(CASE WHEN a.okyn = 'N' THEN NVL(a.qty, '0') ELSE '0' END) OVER () AS TOTALNGQTY FROM T_WMS_LOCATION A LEFT OUTER JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE LEFT OUTER JOIN T_MI_TYPESUB C ON B.CARNO = C.SUBCODE AND C.TYPECODE = 'MI041' WHERE A.USEYN = 'Y'
ORDER BY A.YMDHMS DESC

SELECT x.factory, x.car, x.itemcode, x.itemname, x.spec, SUM(x.okqty) AS okqty, SUM(x.ngqty) AS ngqty,
/* ✅ totals는 “그룹핑된 결과 기준” 총합 */ SUM(SUM(x.qty_num)) OVER () AS totalqty, SUM(SUM(x.okqty)) OVER () AS totalokqty, SUM(SUM(x.ngqty)) OVER () AS totalngqty FROM ( SELECT a.factory, c.subname_ch AS car, a.itemcode, b.itemname, b.spec, TO_NUMBER(TRIM(a.qty)) AS qty_num, CASE WHEN a.okyn = 'Y' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END AS okqty, CASE WHEN a.okyn = 'N' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END AS ngqty FROM t_wms_location a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y'
) x GROUP BY x.factory, x.car, x.itemcode, x.itemname, x.spec ORDER BY x.itemcode

SELECT a.factory, a.storage, a.location, a.source, a.scantype, a.sdate, c.subname_ch AS car, a.itemcode, b.itemname, a.qty, CASE WHEN NVL(o.labeltype, 'NORMAL') != 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END AS ok, CASE WHEN NVL(o.labeltype, 'NORMAL') = 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END AS ng, a.type, a.barcode, a.location, a.lotdate, a.ymdhms, a.loginid, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) as hhmm, b.spec, a.lotdate as bdate, /* ✅ totals는 “그룹핑된 결과 기준” 총합 */ SUM(TO_NUMBER(TRIM(a.qty))) OVER () AS totalqty, /* ✅ ok 합계 */ SUM( CASE WHEN NVL(o.labeltype, 'NORMAL') != 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END ) OVER () AS oktotalqty,
/* ✅ ng 합계 */ SUM( CASE WHEN NVL(o.labeltype, 'NORMAL') = 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END ) OVER () AS ngtotalqty FROM ( SELECT * FROM ( SELECT r.*, ROW_NUMBER() OVER ( PARTITION BY r.barcode ORDER BY r.sdate DESC, r.ymdhms DESC ) AS rn_barcode FROM t_wms_realstock r WHERE r.useyn = 'Y' and r.sdate = #{searchParams.sdate} ) t WHERE rn_barcode = 1
) a
LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' LEFT JOIN t_scm_barcode o ON o.barcode = a.barcode WHERE 1=1 AND a.useyn = 'Y'
ORDER BY a.ymdhms DESC, a.itemcode

SELECT a.factory, a.storage, a.location, a.source, a.scantype, a.sdate, c.subname_ch AS car, a.itemcode, b.itemname, a.qty, CASE WHEN NVL(o.labeltype, 'NORMAL') != 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END AS ok, CASE WHEN NVL(o.labeltype, 'NORMAL') = 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END AS ng, a.type, a.barcode, a.location, a.lotdate, a.ymdhms, a.loginid, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) as hhmm, b.spec, a.lotdate as bdate, /* ✅ totals는 “그룹핑된 결과 기준” 총합 */ SUM(TO_NUMBER(TRIM(a.qty))) OVER () AS totalqty, /* ✅ ok 합계 */ SUM( CASE WHEN NVL(o.labeltype, 'NORMAL') != 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END ) OVER () AS oktotalqty,
/* ✅ ng 합계 */ SUM( CASE WHEN NVL(o.labeltype, 'NORMAL') = 'Defective' THEN TO_NUMBER(TRIM(a.qty)) ELSE 0 END ) OVER () AS ngtotalqty FROM ( SELECT * FROM ( SELECT r.*, ROW_NUMBER() OVER ( PARTITION BY r.barcode ORDER BY r.sdate DESC, r.ymdhms DESC ) AS rn_barcode FROM t_wms_realstock r WHERE r.useyn = 'Y' and r.sdate = #{searchParams.sdate} ) t WHERE rn_barcode = 1
) a
LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' LEFT JOIN t_scm_barcode o ON o.barcode = a.barcode WHERE 1=1 AND a.useyn = 'Y' AND A.SOURCE = 'LASTDAY'
ORDER BY a.ymdhms DESC, a.itemcode

mapper.update:
update t_scm_barcode set useyn ='N',
useyn_ymdhms = to_char(sysdate,'YYYYMMDDHH24MISS')
where barcode = #{barcode}

UPDATE T_WMS_INSPECTION
   SET POSTYN = 'Y'
 WHERE IID = #{iid}

mapper.select:
SELECT A.IID, A.SDATE, A.ITEMCODE, B.ITEMNAME, C.SUBNAME_CH AS CAR, NVL(A.QTY, 0) AS QTY, NVL(A.OKQTY, 0) AS OKQTY, NVL(A.NGQTY, 0) AS NGQTY, A.LINE, A.SOURCE, A.SOURCE2, A.MAINCATEGORY, A.SUBCATEGORY, A.DETAILCATEGORY, A.JUDGMENT, A.CUSTNAME, A.MEMO, A.POSTYN, H.SUBNAME_CH AS UNIT, CASE WHEN A.YMDHMS IS NULL OR TRIM(A.YMDHMS) = '' THEN '' ELSE TO_CHAR( TO_DATE(A.YMDHMS, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS' ) END AS HHMM, A.BARCODE, A.BARCODE2 AS DEFBARCODE,
/* ✅ totals (모든 줄에 동일하게 표시) */ SUM(NVL(A.QTY, 0)) OVER () AS TOTALQTY, SUM(NVL(A.OKQTY, 0)) OVER () AS TOTALOKQTY, SUM(NVL(A.NGQTY, 0)) OVER () AS TOTALNGQTY FROM T_WMS_INSPECTION A LEFT OUTER JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE LEFT OUTER JOIN T_MI_TYPESUB C ON B.CARNO = C.SUBCODE AND C.TYPECODE = 'MI041' LEFT OUTER JOIN T_MI_TYPESUB H ON B.CMB_UNIT = H.SUBCODE AND H.TYPECODE = 'MI001' LEFT OUTER JOIN ( SELECT DISTINCT UNPACKBARCODE FROM T_SCM_BARCODE ) D ON D.UNPACKBARCODE = A.BARCODE WHERE A.USEYN = 'Y' AND UPPER(A.JUDGMENT) = 'DESCOPOSICION'
ORDER BY A.YMDHMS DESC

SELECT A.IID, A.SDATE, A.ITEMCODE, B.ITEMNAME, C.SUBNAME_CH AS CAR, NVL(A.QTY, 0) AS QTY, NVL(A.OKQTY, 0) AS OKQTY, NVL(A.NGQTY, 0) AS NGQTY, A.LINE, A.SOURCE, A.SOURCE2, A.MAINCATEGORY, A.SUBCATEGORY, A.DETAILCATEGORY, A.JUDGMENT, A.CUSTNAME, A.MEMO, A.POSTYN, H.SUBNAME_CH AS UNIT, CASE WHEN A.YMDHMS IS NULL OR TRIM(A.YMDHMS) = '' THEN '' ELSE TO_CHAR( TO_DATE(A.YMDHMS, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS' ) END AS HHMM, A.BARCODE, A.BARCODE2 AS DEFBARCODE,
/* ✅ totals (모든 줄에 동일하게 표시) */ SUM(NVL(A.QTY, 0)) OVER () AS TOTALQTY, SUM(NVL(A.OKQTY, 0)) OVER () AS TOTALOKQTY, SUM(NVL(A.NGQTY, 0)) OVER () AS TOTALNGQTY FROM T_WMS_INSPECTION A LEFT OUTER JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE LEFT OUTER JOIN T_MI_TYPESUB C ON B.CARNO = C.SUBCODE AND C.TYPECODE = 'MI041' LEFT OUTER JOIN T_MI_TYPESUB H ON B.CMB_UNIT = H.SUBCODE AND H.TYPECODE = 'MI001' LEFT OUTER JOIN ( SELECT DISTINCT UNPACKBARCODE FROM T_SCM_BARCODE ) D ON D.UNPACKBARCODE = A.BARCODE WHERE A.USEYN = 'Y' AND UPPER(A.JUDGMENT) = 'SCRAP'
ORDER BY A.YMDHMS DESC

mapper.insert:
insert into t_wms_location (
	indate, ymdhms,location, barcode, itemcode, 
	qty, loginid,factory, storage, source, okyn
) values(
	#{date},to_char(sysdate, 'YYYYMMDDHH24MISS'),#{location},#{barcode},#{itemcode},
	#{qty},#{loginid}, #{factory},#{storage},'INSPECTION',#{okyn}
)

